import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{o as n,c as r,e as o}from"./app.ceeb05d3.js";const e={},t=o('<h2 id="\u4E00\u3001\u4E3A\u4EC0\u4E48\u9700\u8981\u5927\u6A21\u578B\u8BC4\u6D4B" tabindex="-1"><a class="header-anchor" href="#\u4E00\u3001\u4E3A\u4EC0\u4E48\u9700\u8981\u5927\u6A21\u578B\u8BC4\u6D4B" aria-hidden="true">#</a> \u4E00\u3001\u4E3A\u4EC0\u4E48\u9700\u8981\u5927\u6A21\u578B\u8BC4\u6D4B</h2><p>\u5F88\u591A\u5C0F\u4F19\u4F34\u53EF\u80FD\u4F1A\u6709\u8FD9\u6837\u7684\u60F3\u6CD5\uFF1A\u201C\u6211\u8BAD\u7EC3\u5B8C\u6A21\u578B\uFF0C\u81EA\u5DF1\u8BD5\u51E0\u4E2A\u95EE\u9898\u611F\u89C9\u6548\u679C\u4E0D\u9519\uFF0C\u4E0D\u5C31\u8BF4\u660E\u6A21\u578B\u633A\u597D\u7684\u5417\uFF1F\u201D</p><p>\u8FD9\u4E2A\u60F3\u6CD5\u770B\u4F3C\u6709\u9053\u7406\uFF0C\u4F46\u5B9E\u9645\u5DE5\u4F5C\u4E2D\uFF0C\u4EC5\u51ED\u4E3B\u89C2\u611F\u89C9\u6765\u8BC4\u5224\u6A21\u578B\u662F\u8FDC\u8FDC\u4E0D\u591F\u7684\u3002\u4E3B\u8981\u6709\u5982\u4E0B\u51E0\u70B9\u539F\u56E0\uFF1A</p><ol><li><p><strong>\u6A21\u578B\u8BAD\u7EC3\u672C\u8EAB\u9700\u8981\u660E\u786E\u7684\u201C\u65B9\u5411\u611F\u201D</strong>\u3002\u8BAD\u7EC3\u8FC7\u7A0B\u4E2D\u7684Loss\u4E0B\u964D\u53EA\u80FD\u544A\u8BC9\u6A21\u578B\u5728\u201C\u8BB0\u4F4F\u201D\u8BAD\u7EC3\u6570\u636E\uFF0C\u4F46\u65E0\u6CD5\u8BF4\u660E\u6A21\u578B\u7684\u6CDB\u5316\u80FD\u529B\u548C\u5B9E\u9645\u8868\u73B0\u662F\u5426\u771F\u7684\u63D0\u5347\u4E86\u3002\u5C31\u50CF\u5B66\u751F\u5728\u5237\u9898\uFF0C\u5E73\u65F6\u7684\u7EC3\u4E60\u6B63\u786E\u7387\u4E0A\u53BB\u4E86\uFF0C\u4E0D\u4EE3\u8868\u4ED6\u771F\u6B63\u638C\u63E1\u4E86\u77E5\u8BC6\u70B9\uFF0C\u66F4\u4E0D\u4EE3\u8868\u4ED6\u80FD\u5728\u6B63\u5F0F\u8003\u8BD5\u4E2D\u53D6\u5F97\u597D\u6210\u7EE9\u3002</p></li><li><p><strong>\u5728\u6A21\u578B\u9009\u578B\u548C\u8FED\u4EE3\u65F6\uFF0C\u9700\u8981\u6709\u5BA2\u89C2\u7684\u6807\u5C3A\u6765\u8861\u91CF\u4E0D\u540C\u6A21\u578B\u7684\u8868\u73B0</strong>\u3002\u5343\u4EBF\u53C2\u6570\u7684\u5927\u6A21\u578B\u8BAD\u7EC3\u6781\u5176\u70E7\u94B1\uFF0C\u5BF9\u4E8E\u5E95\u5C42\u6A21\u578B\u5382\u5546\u6765\u8BF4\uFF0C\u8BC4\u6D4B\u5206\u6570\u662F\u4F01\u4E1A\u878D\u8D44\u3001\u83B7\u53D6\u7B97\u529B\u8D44\u6E90\u7684\u91CD\u8981\u4F9D\u636E\uFF1B\u5BF9\u4E8E\u4F01\u4E1A\u5BA2\u6237\u6765\u8BF4\uFF0C\u5206\u6570\u662F\u51B3\u5B9A\u662F\u5426\u5C06\u6838\u5FC3\u4E1A\u52A1\u4EA4\u7ED9AI\u6765\u5904\u7406\u7684\u51B3\u7B56\u4F9D\u636E\u3002\u6CA1\u6709\u7EDF\u4E00\u7684\u8BC4\u6D4B\u6807\u51C6\uFF0C\u5C31\u65E0\u4ECE\u5BF9\u6BD4\u6A21\u578B\u7684\u4F18\u52A3\uFF0C\u6280\u672F\u51B3\u7B56\u5C31\u4F1A\u53D8\u6210\u201C\u62CD\u8111\u888B\u201D\u3002</p></li><li><p><strong>\u5927\u6A21\u578B\u8BC4\u6D4B\u662F\u53D1\u73B0\u6A21\u578B\u77ED\u677F\u7684\u91CD\u8981\u624B\u6BB5</strong>\u3002\u5927\u6A21\u578B\u7684\u8BC4\u4F30\u4E0D\u4EC5\u4EC5\u662F\u6280\u672F\u5C42\u9762\u7684\u5DE5\u4F5C\uFF0C\u66F4\u662F\u4F01\u4E1A\u6218\u7565\u51B3\u7B56\u7684\u91CD\u8981\u652F\u6491\uFF0C\u6DB5\u76D6\u4E86\u6A21\u578B\u9009\u578B\u6307\u5BFC\u3001\u4EA7\u54C1\u8D28\u91CF\u4FDD\u969C\u3001\u6280\u672F\u521B\u65B0\u63A8\u52A8\u548C\u751F\u6001\u5065\u5EB7\u53D1\u5C55\u7B49\u591A\u4E2A\u7EF4\u5EA6\u3002\u4E00\u4E2A\u5728\u901A\u7528\u5BF9\u8BDD\u4E2D\u8868\u73B0\u4E0D\u9519\u7684\u6A21\u578B\uFF0C\u53EF\u80FD\u5728\u6570\u5B66\u63A8\u7406\u4E0A\u4E00\u584C\u7CCA\u6D82\uFF0C\u6216\u8005\u5728\u4EE3\u7801\u751F\u6210\u4E0A\u6F0F\u6D1E\u767E\u51FA\u3002\u53EA\u6709\u901A\u8FC7\u7CFB\u7EDF\u5316\u7684\u8BC4\u6D4B\uFF0C\u624D\u80FD\u5168\u9762\u4E86\u89E3\u6A21\u578B\u7684\u771F\u5B9E\u80FD\u529B\u8FB9\u754C\u3002</p></li><li><p><strong>\u4ECE\u5408\u89C4\u548C\u5B89\u5168\u89D2\u5EA6\u6765\u770B\uFF0C\u5927\u6A21\u578B\u8BC4\u6D4B\u4E5F\u662F\u786E\u4FDD\u6A21\u578B\u8F93\u51FA\u7684\u5B89\u5168\u6027\u3001\u516C\u5E73\u6027\u548C\u5408\u89C4\u6027\u7684\u5FC5\u8981\u624B\u6BB5</strong>\u3002\u65E0\u8BBA\u5927\u5BB6\u662F\u505A\u5782\u76F4\u9886\u57DF\u7684\u884C\u4E1A\u6A21\u578B\uFF0C\u8FD8\u662F\u505A\u901A\u7528\u5BF9\u8BDD\u6A21\u578B\uFF0C\u90FD\u9700\u8981\u786E\u4FDD\u6A21\u578B\u5728\u4E0A\u7EBF\u540E\u4E0D\u4F1A\u8F93\u51FA\u6709\u5BB3\u3001\u5192\u72AF\u6027\u6216\u5B58\u5728\u504F\u89C1\u7684\u5185\u5BB9\u3002</p></li></ol><p>\u6B63\u56E0\u4E3A\u5982\u6B64\uFF0C\u5927\u6A21\u578B\u8BC4\u6D4B\u5728\u6574\u4E2A\u5927\u6A21\u578B\u8BAD\u7EC3\u6D41\u7A0B\u4E2D\u5360\u636E\u7740\u81F3\u5173\u91CD\u8981\u7684\u4F4D\u7F6E\u3002\u53EF\u4EE5\u8BF4\uFF0C<strong>\u6CA1\u6709\u7ECF\u8FC7\u4E25\u683C\u8BC4\u6D4B\u7684\u6A21\u578B\uFF0C\u5C31\u6CA1\u6709\u8D44\u683C\u8FDB\u5165\u751F\u4EA7\u73AF\u5883</strong>\u3002</p><h2 id="\u4E8C\u3001\u5927\u6A21\u578B\u8BC4\u6D4B\u7684\u4E09\u5927\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u4E8C\u3001\u5927\u6A21\u578B\u8BC4\u6D4B\u7684\u4E09\u5927\u65B9\u6CD5" aria-hidden="true">#</a> \u4E8C\u3001\u5927\u6A21\u578B\u8BC4\u6D4B\u7684\u4E09\u5927\u65B9\u6CD5</h2><p>\u90A3\u4E48\uFF0C\u5177\u4F53\u8BE5\u600E\u4E48\u8BC4\u6D4B\u4E00\u4E2A\u5927\u6A21\u578B\u5462\uFF1F\u76EE\u524D\u4E1A\u754C\u4E3B\u6D41\u7684\u65B9\u6CD5\u53EF\u4EE5\u5F52\u7EB3\u4E3A\u4E09\u79CD\uFF1A\u4EBA\u5DE5\u8BC4\u6D4B\u3001\u6570\u636E\u96C6\u8BC4\u6D4B\uFF0C\u4EE5\u53CA\u7528\u522B\u7684\u5927\u6A21\u578B\u8FDB\u884C\u81EA\u52A8\u5316\u8BC4\u6D4B\u3002</p><h3 id="_2-1-\u4EBA\u5DE5\u8BC4\u6D4B-\u6700\u76F4\u63A5-\u4F46\u4E5F\u6700\u8D39\u65F6" tabindex="-1"><a class="header-anchor" href="#_2-1-\u4EBA\u5DE5\u8BC4\u6D4B-\u6700\u76F4\u63A5-\u4F46\u4E5F\u6700\u8D39\u65F6" aria-hidden="true">#</a> 2.1 \u4EBA\u5DE5\u8BC4\u6D4B\uFF1A\u6700\u76F4\u63A5\uFF0C\u4F46\u4E5F\u6700\u8D39\u65F6</h3><p>\u4EBA\u5DE5\u8BC4\u6D4B\u662F\u6A21\u578B\u5F00\u53D1\u521D\u671F\u6700\u5E38\u7528\u7684\u624B\u6BB5\u3002\u7531\u4EBA\u5DE5\u8BBE\u8BA1\u8BC4\u6D4B\u6570\u636E\u96C6\u548C\u8BC4\u6D4B\u6307\u6807\u9879\uFF0C\u5BF9\u6A21\u578B\u751F\u6210\u7684\u56DE\u7B54\u8FDB\u884C\u6253\u5206\uFF0C\u8BC4\u6D4B\u5B8C\u6210\u540E\u57FA\u4E8E\u6253\u5206\u7ED3\u679C\u751F\u6210\u8BC4\u6D4B\u62A5\u544A\u3002</p><p>\u5B83\u7684\u4F18\u52BF\u5728\u4E8E\u76F4\u89C2\u3001\u7075\u6D3B\u2014\u2014\u4EBA\u53EF\u4EE5\u76F4\u63A5\u5224\u65AD\u56DE\u7B54\u7684\u8D28\u91CF\u3001\u903B\u8F91\u6027\u3001\u6D41\u7545\u5EA6\u3001\u662F\u5426\u6709\u4E8B\u5B9E\u6027\u9519\u8BEF\u7B49\u7EF4\u5EA6\uFF0C\u8FD9\u4E9B\u90FD\u662F\u673A\u5668\u5F88\u96BE\u81EA\u52A8\u8861\u91CF\u7684\u65B9\u9762\u3002\u5C24\u5176\u5728\u9700\u8981\u8BC4\u4F30\u521B\u9020\u529B\u3001\u5E7D\u9ED8\u611F\u3001\u7528\u6237\u4F53\u9A8C\u7B49\u4E3B\u89C2\u7EF4\u5EA6\u65F6\uFF0C\u4EBA\u5DE5\u8BC4\u6D4B\u51E0\u4E4E\u662F\u4E0D\u53EF\u66FF\u4EE3\u7684\u3002</p><p>\u4F46\u4EBA\u5DE5\u8BC4\u6D4B\u7684\u5C40\u9650\u4E5F\u975E\u5E38\u660E\u663E\uFF1A\u6548\u7387\u4F4E\u3001\u6210\u672C\u9AD8\u3001\u4E00\u81F4\u6027\u5DEE\u3002\u4E00\u4E2A\u56E2\u961F\u624B\u52A8\u68C0\u67E51000\u6761\u751F\u6210\u7ED3\u679C\u53EF\u80FD\u9700\u8981\u6570\u5C0F\u65F6\uFF0C\u800C\u4E14\u4E0D\u540C\u4EBA\u5BF9\u540C\u4E00\u56DE\u7B54\u7684\u8BC4\u5206\u53EF\u80FD\u5B58\u572830%\u4EE5\u4E0A\u7684\u504F\u5DEE\u3002\u56E0\u6B64\uFF0C\u4EBA\u5DE5\u8BC4\u6D4B\u901A\u5E38\u4E0D\u4F1A\u4F5C\u4E3A\u5927\u89C4\u6A21\u7684\u5E38\u89C4\u8BC4\u6D4B\u624B\u6BB5\uFF0C\u800C\u66F4\u591A\u7528\u4E8E\u6A21\u578B\u5F00\u53D1\u65E9\u671F\u7684\u5B9A\u6027\u5224\u65AD\u548C\u4E0A\u7EBF\u524D\u7684\u6700\u7EC8\u628A\u5173\u3002</p><h3 id="_2-2-\u6570\u636E\u96C6\u8BC4\u6D4B-\u6807\u51C6\u5316\u3001\u53EF\u590D\u73B0\u7684-\u7EDF\u8003" tabindex="-1"><a class="header-anchor" href="#_2-2-\u6570\u636E\u96C6\u8BC4\u6D4B-\u6807\u51C6\u5316\u3001\u53EF\u590D\u73B0\u7684-\u7EDF\u8003" aria-hidden="true">#</a> 2.2 \u6570\u636E\u96C6\u8BC4\u6D4B\uFF1A\u6807\u51C6\u5316\u3001\u53EF\u590D\u73B0\u7684\u201C\u7EDF\u8003\u201D</h3><p>\u6570\u636E\u96C6\u8BC4\u6D4B\u662F\u76EE\u524D\u6700\u4E3B\u6D41\u3001\u4E5F\u662F\u6700\u5177\u53C2\u8003\u4EF7\u503C\u7684\u8BC4\u6D4B\u65B9\u5F0F\u3002\u5B83\u7684\u601D\u8DEF\u5F88\u7B80\u5355\uFF1A\u7528\u4E00\u5957\u6807\u51C6\u7684\u201C\u8003\u9898\u201D\uFF08\u8BC4\u6D4B\u6570\u636E\u96C6\uFF09\u6765\u6D4B\u8BD5\u6A21\u578B\uFF0C\u7136\u540E\u901A\u8FC7\u9884\u8BBE\u7684\u8BC4\u5206\u89C4\u5219\u6216\u6307\u6807\u6765\u91CF\u5316\u6A21\u578B\u7684\u8868\u73B0\u3002</p><p>\u6253\u4E2A\u6BD4\u65B9\uFF0C\u8FD9\u5C31\u50CF\u5927\u6A21\u578B\u754C\u7684\u201C\u9AD8\u8003\u201D\u2014\u2014\u7EDF\u4E00\u7684\u8BD5\u5377\uFF0C\u7EDF\u4E00\u7684\u8BC4\u5206\u6807\u51C6\uFF0C\u8C01\u9AD8\u8C01\u4F4E\u4E00\u76EE\u4E86\u7136\u3002</p><p>\u6570\u636E\u96C6\u8BC4\u6D4B\u7684\u4F18\u52BF\u5728\u4E8E\u6807\u51C6\u5316\u3001\u53EF\u590D\u73B0\u3001\u53EF\u5BF9\u6BD4\u3002\u540C\u6837\u7684\u6570\u636E\u96C6\u3001\u540C\u6837\u7684\u8BC4\u6D4B\u6D41\u7A0B\uFF0C\u53EF\u4EE5\u5BF9\u4E0D\u540C\u6A21\u578B\u8FDB\u884C\u516C\u5E73\u7684\u6A2A\u5411\u5BF9\u6BD4\u3002\u76EE\u524D\u4E1A\u754C\u5DF2\u7ECF\u79EF\u7D2F\u4E86\u5927\u91CF\u7684\u516C\u5F00\u8BC4\u6D4B\u6570\u636E\u96C6\uFF0C\u8986\u76D6\u4E86\u901A\u7528\u77E5\u8BC6\u3001\u6570\u5B66\u63A8\u7406\u3001\u4EE3\u7801\u751F\u6210\u3001\u4E2D\u6587\u7406\u89E3\u7B49\u5404\u4E2A\u7EF4\u5EA6\uFF0C\u7B14\u8005\u5728\u540E\u6587\u4F1A\u8BE6\u7EC6\u4ECB\u7ECD\u3002</p><p>\u4E0D\u8FC7\uFF0C\u6570\u636E\u96C6\u8BC4\u6D4B\u4E5F\u6709\u9700\u8981\u6CE8\u610F\u7684\u5730\u65B9\u3002\u4E00\u662F\u6570\u636E\u6C61\u67D3\u95EE\u9898\u2014\u2014\u5982\u679C\u6A21\u578B\u5728\u8BAD\u7EC3\u8FC7\u7A0B\u4E2D\u201C\u89C1\u8FC7\u201D\u6D4B\u8BD5\u96C6\uFF0C\u8BC4\u6D4B\u5206\u6570\u5C31\u4F1A\u5931\u771F\u3002\u4E8C\u662F\u57FA\u51C6\u6D4B\u8BD5\u4E0E\u73B0\u5B9E\u5E94\u7528\u4E4B\u95F4\u53EF\u80FD\u5B58\u5728\u8131\u8282\u2014\u2014\u5728\u6807\u51C6\u6570\u636E\u96C6\u4E0A\u8868\u73B0\u4F18\u5F02\u7684\u6A21\u578B\uFF0C\u5728\u5B9E\u9645\u573A\u666F\u4E2D\u672A\u5FC5\u540C\u6837\u51FA\u8272\u3002</p><h3 id="_2-3-\u5927\u6A21\u578B\u81EA\u52A8\u5316\u8BC4\u6D4B-\u7528\u5927\u6A21\u578B\u8BC4\u5927\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#_2-3-\u5927\u6A21\u578B\u81EA\u52A8\u5316\u8BC4\u6D4B-\u7528\u5927\u6A21\u578B\u8BC4\u5927\u6A21\u578B" aria-hidden="true">#</a> 2.3 \u5927\u6A21\u578B\u81EA\u52A8\u5316\u8BC4\u6D4B\uFF1A\u7528\u5927\u6A21\u578B\u8BC4\u5927\u6A21\u578B</h3><p>\u8FD9\u662F\u5DF2\u7ECF\u5177\u5907GPT,Claude\u7B49\u8F83\u5F3A\u5927\u6A21\u578B\u57FA\u7840\u540E\u5174\u8D77\u7684\u4E00\u79CD\u65B0\u578B\u8BC4\u6D4B\u65B9\u5F0F\u3002\u6838\u5FC3\u601D\u8DEF\u662F\u7528\u4E00\u4E2A\u80FD\u529B\u66F4\u5F3A\u7684\u201C\u88C1\u5224\u6A21\u578B\u201D\u6765\u5BF9\u88AB\u8BC4\u6D4B\u6A21\u578B\u7684\u751F\u6210\u7ED3\u679C\u8FDB\u884C\u6253\u5206\u3002\u8FD9\u79CD\u65B9\u5F0F\u7279\u522B\u9002\u5408\u5F00\u653E\u6027\u95EE\u7B54\u6216\u590D\u6742\u5BF9\u8BDD\u573A\u666F\u2014\u2014\u8FD9\u7C7B\u4EFB\u52A1\u6CA1\u6709\u6807\u51C6\u7B54\u6848\uFF0C\u4F20\u7EDF\u7684\u57FA\u4E8E\u89C4\u5219\u6216\u76F8\u4F3C\u5EA6\u5339\u914D\u7684\u8BC4\u6D4B\u65B9\u5F0F\u65E0\u6CD5\u80DC\u4EFB\u3002</p><p>\u88C1\u5224\u6A21\u578B\u8BC4\u6D4B\u53EF\u4EE5\u652F\u6301\u8BC4\u5206\u6A21\u5F0F\u548C\u5BF9\u6BD4\u6A21\u5F0F\u3002\u8BC4\u5206\u6A21\u5F0F\u4E0B\uFF0C\u88C1\u5224\u6A21\u578B\u5BF9\u88AB\u8BC4\u6D4B\u6A21\u578B\u7684\u56DE\u7B54\u7ED9\u51FA\u4E00\u4E2A\u5206\u6570\uFF1B\u5BF9\u6BD4\u6A21\u5F0F\u4E0B\uFF0C\u88C1\u5224\u6A21\u578B\u76F4\u63A5\u6BD4\u8F83\u4E24\u4E2A\u6A21\u578B\u7684\u56DE\u7B54\u8D28\u91CF\uFF0C\u8F93\u51FA\u80DC\u8D1F\u5224\u65AD\u3002</p><p>\u8FD9\u79CD\u65B9\u5F0F\u7684\u597D\u5904\u662F\u517C\u987E\u4E86\u81EA\u52A8\u5316\u7684\u6548\u7387\u548C\u4EBA\u5DE5\u8BC4\u6D4B\u7684\u7075\u6D3B\u6027\uFF0C\u4F46\u4E5F\u5B58\u5728\u4E00\u5B9A\u7684\u4E89\u8BAE\u2014\u2014\u88C1\u5224\u6A21\u578B\u81EA\u8EAB\u7684\u504F\u597D\u548C\u504F\u5DEE\u53EF\u80FD\u4F1A\u5F71\u54CD\u8BC4\u5206\u7ED3\u679C\uFF0C\u56E0\u6B64\u5728\u4F7F\u7528\u65F6\u9700\u8981\u8C28\u614E\u8BBE\u8BA1\u8BC4\u6D4BPrompt\uFF0C\u5E76\u5BF9\u88C1\u5224\u6A21\u578B\u7684\u53EF\u9760\u6027\u8FDB\u884C\u9A8C\u8BC1\u3002</p><blockquote><p>\u5C0F\u8D34\u58EB\uFF1A\u4E09\u79CD\u8BC4\u6D4B\u65B9\u5F0F\u5404\u6709\u9002\u7528\u573A\u666F\uFF0C\u5B9E\u9645\u5DE5\u4F5C\u4E2D\u5F80\u5F80\u9700\u8981\u7EC4\u5408\u4F7F\u7528\u2014\u2014\u7528\u6570\u636E\u96C6\u8BC4\u6D4B\u505A\u5927\u89C4\u6A21\u3001\u6807\u51C6\u5316\u7684\u80FD\u529B\u6D4B\u8BD5\uFF0C\u7528\u81EA\u52A8\u5316\u8BC4\u6D4B\u505A\u5F00\u653E\u6027\u4EFB\u52A1\u7684\u8BC4\u4F30\uFF0C\u6700\u540E\u7528\u4EBA\u5DE5\u62BD\u68C0\u505A\u6700\u7EC8\u7684\u8D28\u91CF\u628A\u5173\u3002</p></blockquote><h2 id="\u4E09\u3001\u5178\u578B\u5927\u6A21\u578B\u8BC4\u6D4B\u6570\u636E\u96C6\u6982\u89C8" tabindex="-1"><a class="header-anchor" href="#\u4E09\u3001\u5178\u578B\u5927\u6A21\u578B\u8BC4\u6D4B\u6570\u636E\u96C6\u6982\u89C8" aria-hidden="true">#</a> \u4E09\u3001\u5178\u578B\u5927\u6A21\u578B\u8BC4\u6D4B\u6570\u636E\u96C6\u6982\u89C8</h2><p>\u4E86\u89E3\u4E86\u8BC4\u6D4B\u65B9\u6CD5\u4E4B\u540E\uFF0C\u7B14\u8005\u548C\u5927\u5BB6\u4E00\u8D77\u6765\u8BA4\u8BC6\u4E00\u4E0B\u4E1A\u754C\u6700\u5E38\u7528\u3001\u6700\u5177\u4EE3\u8868\u6027\u7684\u51E0\u7C7B\u8BC4\u6D4B\u6570\u636E\u96C6\u3002\u8FD9\u4E9B\u6570\u636E\u96C6\u5C31\u50CF\u5927\u6A21\u578B\u754C\u7684\u201C\u8003\u8BD5\u79D1\u76EE\u201D\uFF0C\u6BCF\u4E00\u95E8\u90FD\u5728\u8003\u5BDF\u6A21\u578B\u4E0D\u540C\u7684\u80FD\u529B\u3002</p><h3 id="_3-1-\u901A\u7528\u77E5\u8BC6\u4E0E\u8BED\u8A00\u7406\u89E3" tabindex="-1"><a class="header-anchor" href="#_3-1-\u901A\u7528\u77E5\u8BC6\u4E0E\u8BED\u8A00\u7406\u89E3" aria-hidden="true">#</a> 3.1 \u901A\u7528\u77E5\u8BC6\u4E0E\u8BED\u8A00\u7406\u89E3</h3><ul><li><p><strong>MMLU</strong>\uFF1A\u4F2F\u514B\u5229\u5927\u5B66\u7B49\u8054\u5408\u53D1\u5E03\u7684\u5927\u89C4\u6A21\u591A\u4EFB\u52A1\u8BED\u8A00\u7406\u89E3\u57FA\u51C6\u6D4B\u8BD5\uFF0C\u5305\u542B57\u4E2A\u5B66\u79D1\u9886\u57DF\uFF0C\u6DB5\u76D6STEM\u3001\u4EBA\u6587\u3001\u793E\u4F1A\u79D1\u5B66\u7B49\uFF0C\u517115908\u9053\u9009\u62E9\u9898\uFF0C\u662F\u76EE\u524D\u6700\u6743\u5A01\u7684\u82F1\u6587\u901A\u7528\u77E5\u8BC6\u8BC4\u6D4B\u6570\u636E\u96C6\u4E4B\u4E00\u3002\u4F46\u7531\u4E8E\u8BB8\u591A\u6A21\u578B\u5DF2\u7ECF\u5728MMLU\u4E0A\u5DF2\u7ECF\u63A5\u8FD1\u9971\u548C\uFF08&gt;90%\u51C6\u786E\u7387\uFF09\uFF0C\u56E0\u6B64\u4E1A\u754C\u53C8\u63A8\u51FA\u4E86\u66F4\u5177\u6311\u6218\u6027\u7684<strong>MMLU-Pro</strong>\u7248\u672C\u3002</p></li><li><p><strong>C-Eval</strong>\uFF1A\u4E2D\u6587\u9886\u57DF\u7684\u201CMMLU\u201D\uFF0C\u7531\u4E0A\u6D77\u4EA4\u901A\u5927\u5B66\u3001\u6E05\u534E\u5927\u5B66\u548C\u7231\u4E01\u5821\u5927\u5B66\u8054\u5408\u53D1\u5E03\uFF0C\u5305\u542B13948\u9053\u9009\u62E9\u9898\uFF0C\u8986\u76D652\u4E2A\u5B66\u79D1\u548C\u56DB\u4E2A\u96BE\u5EA6\u7EA7\u522B\uFF0C\u662F\u8BC4\u6D4B\u4E2D\u6587\u6A21\u578B\u57FA\u7840\u80FD\u529B\u7684\u6743\u5A01\u57FA\u51C6\u3002</p></li><li><p><strong>CMMLU</strong>\uFF1A\u53E6\u4E00\u4E2A\u5168\u9762\u7684\u4E2D\u6587\u8BC4\u6D4B\u6570\u636E\u96C6\uFF0C\u8986\u76D667\u4E2A\u4E3B\u9898\uFF0C\u4ECE\u57FA\u7840\u5B66\u79D1\u5230\u9AD8\u7EA7\u4E13\u4E1A\u77E5\u8BC6\u5747\u6709\u6D89\u53CA\uFF0C\u4E0EC-Eval\u4E92\u4E3A\u8865\u5145\u3002</p></li></ul><h3 id="_3-2-\u6570\u5B66\u4E0E\u903B\u8F91\u63A8\u7406" tabindex="-1"><a class="header-anchor" href="#_3-2-\u6570\u5B66\u4E0E\u903B\u8F91\u63A8\u7406" aria-hidden="true">#</a> 3.2 \u6570\u5B66\u4E0E\u903B\u8F91\u63A8\u7406</h3><ul><li><p><strong>GSM8K</strong>\uFF1AOpenAI\u53D1\u5E03\u7684\u5C0F\u5B66\u6570\u5B66\u5E94\u7528\u9898\u6570\u636E\u96C6\uFF0C\u5305\u542B8500\u9053\u9AD8\u8D28\u91CF\u6570\u5B66\u9898\uFF0C\u662F\u76EE\u524D\u6700\u5E38\u7528\u7684\u6570\u5B66\u63A8\u7406\u80FD\u529B\u8BC4\u6D4B\u57FA\u51C6-\u3002\u867D\u7136\u9898\u76EE\u662F\u5C0F\u5B66\u6570\u5B66\u6C34\u5E73\uFF0C\u4F46\u5BF9\u5927\u6A21\u578B\u7684\u591A\u6B65\u63A8\u7406\u80FD\u529B\u6709\u5F88\u9AD8\u7684\u8981\u6C42\u3002</p></li><li><p><strong>MATH</strong>\uFF1A\u6BD4GSM8K\u66F4\u96BE\u4E00\u4E2A\u6863\u6B21\u7684\u6570\u5B66\u8BC4\u6D4B\u96C6\uFF0C\u5305\u542B12500\u9053\u9AD8\u4E2D\u6570\u5B66\u7ADE\u8D5B\u9898\uFF0C\u9700\u8981\u6A21\u578B\u5177\u5907\u8F83\u5F3A\u7684\u6570\u5B66\u63A8\u7406\u548C\u8BA1\u7B97\u80FD\u529B\u3002</p></li><li><p><strong>BBH</strong>\uFF1A\u5305\u542B204\u9879\u56F0\u96BE\u4EFB\u52A1\u7684\u6570\u636E\u96C6\uFF0C\u8986\u76D6\u8BED\u8A00\u5B66\u3001\u5E38\u8BC6\u63A8\u7406\u3001\u8F6F\u4EF6\u5F00\u53D1\u7B49\u591A\u4E2A\u9886\u57DF\uFF0C\u4E13\u95E8\u8BC4\u6D4B\u6A21\u578B\u5904\u7406\u9AD8\u96BE\u5EA6\u4EFB\u52A1\u7684\u80FD\u529B\u3002</p></li></ul><h3 id="_3-3-\u4EE3\u7801\u751F\u6210\u4E0E\u8F6F\u4EF6\u5DE5\u7A0B" tabindex="-1"><a class="header-anchor" href="#_3-3-\u4EE3\u7801\u751F\u6210\u4E0E\u8F6F\u4EF6\u5DE5\u7A0B" aria-hidden="true">#</a> 3.3 \u4EE3\u7801\u751F\u6210\u4E0E\u8F6F\u4EF6\u5DE5\u7A0B</h3><ul><li><p><strong>HumanEval</strong>\uFF1AOpenAI\u53D1\u5E03\u7684\u4EE3\u7801\u80FD\u529B\u6D4B\u8BD5\u96C6\uFF0C\u5305\u542B164\u9053\u624B\u5199\u7F16\u7A0B\u9898\uFF0C\u8981\u6C42\u6839\u636E\u81EA\u7136\u8BED\u8A00\u63CF\u8FF0\u751F\u6210\u6B63\u786E\u7684\u4EE3\u7801\u7247\u6BB5\u3002\u8BC4\u6D4B\u6307\u6807\u91C7\u7528Pass@k\uFF0C\u5373\u751F\u6210k\u4E2A\u7B54\u6848\u4E2D\u81F3\u5C11\u6709\u4E00\u4E2A\u901A\u8FC7\u6240\u6709\u6D4B\u8BD5\u7528\u4F8B\u7684\u95EE\u9898\u5360\u6BD4\u3002</p></li><li><p><strong>SWE-Bench</strong>\uFF1A\u7531\u666E\u6797\u65AF\u987F\u5927\u5B66\u3001\u65AF\u5766\u798F\u5927\u5B66\u7B49\u8054\u5408\u53D1\u5E03\u7684\u8F6F\u4EF6\u5DE5\u7A0B\u57FA\u51C6\u6D4B\u8BD5\u96C6\uFF0C\u5305\u542B\xA0<strong>2294 \u4E2A\u771F\u5B9E\u7684 GitHub Issue-Solution \u5BF9</strong>\u3002\u6BCF\u4E2A\u6837\u672C\u8981\u6C42\u6A21\u578B\u6839\u636E\u7ED9\u5B9A\u7684\u4EE3\u7801\u4ED3\u5E93\u548C Issue \u63CF\u8FF0\uFF08\u5982\u4FEE\u590D bug\u3001\u6DFB\u52A0\u529F\u80FD\uFF09\uFF0C\u751F\u6210\u6B63\u786E\u7684\u4EE3\u7801\u8865\u4E01\uFF08patch\uFF09\uFF0C\u7136\u540E\u901A\u8FC7\u5355\u5143\u6D4B\u8BD5\u9A8C\u8BC1\u8865\u4E01\u662F\u5426\u771F\u6B63\u89E3\u51B3\u4E86\u95EE\u9898\u3002SWE-Bench \u53CD\u6620\u4E86\u6A21\u578B\u5728\u5B9E\u9645\u8F6F\u4EF6\u5DE5\u7A0B\u4EFB\u52A1\u4E2D\u7684\u8868\u73B0\uFF0C\u662F\u76EE\u524D\u8BC4\u6D4B\u5927\u6A21\u578B\u7F16\u7A0B\u80FD\u529B\u548C\u81EA\u52A8\u5316\u4FEE\u590D\u80FD\u529B\u7684\u91CD\u8981\u57FA\u51C6\u3002\u8FD1\u5E74\u6765\u53C8\u884D\u751F\u51FA\xA0<strong>SWE-Bench Verified</strong>\uFF08\u7ECF\u8FC7\u4EBA\u5DE5\u9A8C\u8BC1\u7684\u5B50\u96C6\uFF0C\u66F4\u53EF\u9760\uFF09\u3001<strong>SWE-Bench Multilingual</strong>\uFF08\u591A\u8BED\u8A00\u7248\u672C\uFF09\u7B49\u53D8\u4F53\u3002\u5982\u679C\u4F60\u5728\u8BAD\u7EC3 Coding Agent \u6216\u505A\u4EE3\u7801\u81EA\u52A8\u5316\u4FEE\u590D\uFF0CSWE-Bench \u662F\u5FC5\u6D4B\u7684\u6570\u636E\u96C6\u3002</p></li></ul><h3 id="_3-4-\u7EFC\u5408\u8003\u8BD5\u4E0E\u4E13\u4E1A\u77E5\u8BC6" tabindex="-1"><a class="header-anchor" href="#_3-4-\u7EFC\u5408\u8003\u8BD5\u4E0E\u4E13\u4E1A\u77E5\u8BC6" aria-hidden="true">#</a> 3.4 \u7EFC\u5408\u8003\u8BD5\u4E0E\u4E13\u4E1A\u77E5\u8BC6</h3><ul><li><p><strong>AGIEval</strong>\uFF1A\u5FAE\u8F6F\u7814\u7A76\u9662\u53D1\u5E03\u7684\u8BC4\u6D4B\u57FA\u51C6\uFF0C\u9009\u53D620\u79CD\u9762\u5411\u666E\u901A\u4EBA\u7C7B\u8003\u751F\u7684\u5B98\u65B9\u6807\u51C6\u5316\u8003\u8BD5\u9898\u76EE\uFF0C\u5305\u62EC\u9AD8\u8003\u3001\u53F8\u6CD5\u8003\u8BD5\u3001\u6570\u5B66\u7ADE\u8D5B\u3001\u5F8B\u5E08\u8D44\u683C\u8003\u8BD5\u7B49\uFF0C\u5168\u9762\u8003\u5BDF\u6A21\u578B\u7684\u8BA4\u77E5\u80FD\u529B\u548C\u77E5\u8BC6\u638C\u63E1\u7A0B\u5EA6\u3002</p></li><li><p><strong>GPQA Diamond</strong>\uFF1A\u7531\u751F\u7269\u5B66\u3001\u7269\u7406\u5B66\u548C\u5316\u5B66\u9886\u57DF\u4E13\u5BB6\u7F16\u5199\u7684\u591A\u9009\u95EE\u7B54\u6570\u636E\u96C6\uFF0C\u5305\u542B448\u4E2A\u6781\u5176\u56F0\u96BE\u7684\u95EE\u9898\uFF0C\u4E13\u95E8\u7528\u4E8E\u8BC4\u6D4B\u6A21\u578B\u5728\u8DE8\u5B66\u79D1\u590D\u6742\u95EE\u9898\u4E0A\u7684\u8868\u73B0\u3002</p></li></ul><blockquote><p>\u9009\u578B\u5EFA\u8BAE\uFF1A\u505A\u901A\u7528\u6A21\u578B\u8BC4\u6D4B\uFF0C\u5EFA\u8BAE\u81F3\u5C11\u8986\u76D6MMLU\uFF08\u82F1\u6587\uFF09\u3001C-Eval\uFF08\u4E2D\u6587\uFF09\u3001GSM8K\uFF08\u6570\u5B66\uFF09\u548CHumanEval\uFF08\u4EE3\u7801\uFF09\u8FD9\u56DB\u4E2A\u7EF4\u5EA6\u3002\u5982\u679C\u662F\u91D1\u878D\u3001\u533B\u7597\u7B49\u4E13\u4E1A\u9886\u57DF\uFF0C\u8FD8\u9700\u8981\u5F15\u5165\u76F8\u5E94\u9886\u57DF\u7684\u8BC4\u6D4B\u6570\u636E\u96C6\u3002</p></blockquote><h2 id="\u56DB\u3001\u5E38\u7528\u8BC4\u6D4B\u5DE5\u5177" tabindex="-1"><a class="header-anchor" href="#\u56DB\u3001\u5E38\u7528\u8BC4\u6D4B\u5DE5\u5177" aria-hidden="true">#</a> \u56DB\u3001\u5E38\u7528\u8BC4\u6D4B\u5DE5\u5177</h2><p>\u6709\u4E86\u524D\u6587\u7684\u8BC4\u6D4B\u65B9\u6CD5\u548C\u6570\u636E\u96C6\uFF0C\u63A5\u4E0B\u6765\u5C31\u662F\u201C\u600E\u4E48\u6D4B\u201D\u7684\u95EE\u9898\u3002\u4EBA\u5DE5\u8BC4\u6D4B\u8FD9\u91CC\u5C31\u4E0D\u5C55\u5F00\u4E86\uFF0C\u7B14\u8005\u91CD\u70B9\u4ECB\u7ECD<strong>\u6570\u636E\u96C6\u6D4B\u8BD5\u5DE5\u5177</strong>\u548C<strong>\u5927\u6A21\u578B\u8BC4\u6D4B\u4E2D\u7684\u63D0\u793A\u8BCD\u8BBE\u8BA1</strong>\u3002</p><h3 id="_4-1-\u6570\u636E\u96C6\u6D4B\u8BD5-evalscope-\u4E00\u7AD9\u5F0F\u641E\u5B9A" tabindex="-1"><a class="header-anchor" href="#_4-1-\u6570\u636E\u96C6\u6D4B\u8BD5-evalscope-\u4E00\u7AD9\u5F0F\u641E\u5B9A" aria-hidden="true">#</a> 4.1 \u6570\u636E\u96C6\u6D4B\u8BD5\uFF1AEvalScope \u4E00\u7AD9\u5F0F\u641E\u5B9A</h3><p>\u6570\u636E\u96C6\u6D4B\u8BD5\u662F\u6700\u6807\u51C6\u5316\u7684\u8BC4\u6D4B\u65B9\u5F0F\uFF0C\u65E0\u8BBA\u516C\u5F00\u57FA\u51C6\u6570\u636E\u96C6\u8FD8\u662F\u81EA\u5DF1\u6784\u9020\u7684\u4E1A\u52A1\u6570\u636E\u96C6\uFF0C\u90FD\u53EF\u4EE5\u501F\u52A9\u5DE5\u5177\u9AD8\u6548\u5B8C\u6210\u3002\u8FD9\u91CC\u5F3A\u70C8\u63A8\u8350\xA0<strong>EvalScope</strong>\u2014\u2014\u9B54\u642D\u793E\u533A\uFF08ModelScope\uFF09\u5B98\u65B9\u5F00\u6E90\u7684\u8F7B\u91CF\u7EA7\u5927\u6A21\u578B\u8BC4\u6D4B\u6846\u67B6\u3002</p><p><strong>EvalScope \u7684\u6838\u5FC3\u4F18\u52BF</strong>\uFF1A</p><ul><li><p><strong>\u5185\u7F6E\u4E3B\u6D41\u6570\u636E\u96C6</strong>\uFF1A\u5F00\u7BB1\u5373\u652F\u6301 MMLU\u3001C-Eval\u3001CMMLU\u3001GSM8K\u3001MATH\u3001HumanEval\u3001SWE-Bench \u7B49 20+ \u4E2A\u4E1A\u754C\u516C\u8BA4\u7684\u8BC4\u6D4B\u57FA\u51C6\uFF0C\u65E0\u9700\u624B\u52A8\u4E0B\u8F7D\u548C\u9884\u5904\u7406\u3002</p></li><li><p><strong>\u652F\u6301\u81EA\u5B9A\u4E49\u6570\u636E\u96C6</strong>\uFF1A\u9664\u4E86\u516C\u5F00\u6570\u636E\u96C6\uFF0C\u4F60\u8FD8\u53EF\u4EE5\u628A\u81EA\u5DF1\u6784\u9020\u7684\u95EE\u7B54\u6570\u636E\u96C6\uFF08CSV / JSONL \u683C\u5F0F\uFF09\u4EA4\u7ED9 EvalScope\uFF0C\u5B8C\u6210\u8BC4\u6D4B\u5168\u6D41\u7A0B\u3002</p></li><li><p><strong>\u81EA\u52A8\u8BA1\u7B97\u6307\u6807</strong>\uFF1A\u6839\u636E\u6570\u636E\u96C6\u7C7B\u578B\u81EA\u52A8\u5339\u914D\u8BC4\u6D4B\u6307\u6807\uFF08\u5982\u51C6\u786E\u7387\u3001BLEU\u3001Rouge\u3001Pass@k \u7B49\uFF09\uFF0C\u8F93\u51FA\u7ED3\u6784\u5316\u62A5\u544A\u3002</p></li><li><p><strong>\u53EF\u89C6\u5316\u4E0E\u5BF9\u6BD4</strong>\uFF1A\u63D0\u4F9B WebUI \u754C\u9762\uFF0C\u652F\u6301\u591A\u6A21\u578B\u5BF9\u6BD4\u548C\u7ADE\u6280\u573A\u6A21\u5F0F\u3002</p></li><li><p><strong>\u591A\u6A21\u578B\u517C\u5BB9</strong>\uFF1A\u652F\u6301\u672C\u5730 HuggingFace \u6A21\u578B\u3001OpenAI API \u517C\u5BB9\u63A5\u53E3\u3001\u9B54\u642D\u793E\u533A\u6A21\u578B\u7B49\u3002</p></li></ul><p>\u5728\u4E13\u4E1A\u9886\u57DF\u8BC4\u6D4B\u4E2D\uFF0CEvalScope \u652F\u6301\u4E24\u79CD\u6570\u636E\u96C6\u6D4B\u8BD5\u5F62\u5F0F\uFF1A</p><ol><li><p><strong>\u516C\u5F00\u57FA\u51C6\u6570\u636E\u96C6\u6D4B\u8BD5</strong>\uFF1A\u6307\u5B9A\u6A21\u578B\u548C\u6570\u636E\u96C6\u540D\u79F0\uFF08\u5982\xA0<code>mmlu</code>\u3001<code>gsm8k</code>\uFF09\uFF0CEvalScope \u81EA\u52A8\u5B8C\u6210\u6570\u636E\u52A0\u8F7D\u3001\u6A21\u578B\u63A8\u7406\u3001\u6307\u6807\u8BA1\u7B97\u3002\u8FD9\u4E3B\u8981\u7528\u4E8E\u9A8C\u8BC1\u6A21\u578B\u5728\u8BAD\u7EC3\u540E\u662F\u5426\u4FDD\u6301\u4E86\u901A\u7528\u80FD\u529B\u3002</p></li><li><p><strong>\u81EA\u5B9A\u4E49\u95EE\u7B54\u6570\u636E\u96C6\u6D4B\u8BD5</strong>\uFF1A\u6309\u7167\u9884\u8BBE\u683C\u5F0F\u51C6\u5907\u597D\u4E1A\u52A1\u6570\u636E\uFF0C\u901A\u8FC7\u53C2\u6570\u6307\u5B9A\u672C\u5730\u8DEF\u5F84\uFF0CEvalScope \u5373\u53EF\u5B8C\u6210\u8BC4\u6D4B\u3002\u4F60\u8FD8\u53EF\u4EE5\u5C06\u591A\u4E2A\u81EA\u5B9A\u4E49\u6570\u636E\u96C6\u7EC4\u5408\u6210\u201C\u8BC4\u6D4B\u96C6\u5408\u201D\uFF0C\u6309\u4E1A\u52A1\u91CD\u8981\u7A0B\u5EA6\u5206\u914D\u6743\u91CD\uFF0C\u4E00\u6B21\u6027\u5F97\u5230\u8D34\u5408\u771F\u5B9E\u573A\u666F\u7684\u7EFC\u5408\u8BC4\u5206\u3002\u8FD9\u4E3B\u8981\u7528\u4E8E\u8BC4\u4F30\u4E13\u4E1A\u9886\u57DF\u6A21\u578B\u5728\u8BAD\u7EC3\u540E\u6548\u679C\u662F\u5426\u6709\u5B9E\u8D28\u6027\u63D0\u5347\u3002</p></li></ol><blockquote><p>\u5C0F\u8D34\u58EB\uFF1A\u81EA\u5B9A\u4E49\u6570\u636E\u96C6\u5EFA\u8BAE\u63A7\u5236\u5728 100~500 \u6761\u9AD8\u8D28\u91CF\u6837\u672C\uFF0C\u8986\u76D6\u4E1A\u52A1\u4E2D\u7684\u9AD8\u9891\u3001\u9AD8\u4EF7\u503C\u573A\u666F\u3002\u6570\u636E\u8D28\u91CF\u8FDC\u6BD4\u6570\u91CF\u91CD\u8981\u3002</p></blockquote><h3 id="_4-2-\u5927\u6A21\u578B\u8BC4\u6D4B\u4E2D\u7684\u63D0\u793A\u8BCD\u8BBE\u8BA1-\u9700\u8981\u4F60\u81EA\u5DF1\u52A8\u624B" tabindex="-1"><a class="header-anchor" href="#_4-2-\u5927\u6A21\u578B\u8BC4\u6D4B\u4E2D\u7684\u63D0\u793A\u8BCD\u8BBE\u8BA1-\u9700\u8981\u4F60\u81EA\u5DF1\u52A8\u624B" aria-hidden="true">#</a> 4.2 \u5927\u6A21\u578B\u8BC4\u6D4B\u4E2D\u7684\u63D0\u793A\u8BCD\u8BBE\u8BA1\uFF1A\u9700\u8981\u4F60\u81EA\u5DF1\u52A8\u624B</h3><p>\u9664\u4E86\u6570\u636E\u96C6\u6D4B\u8BD5\uFF0C\u8FD8\u6709\u4E00\u79CD\u91CD\u8981\u7684\u8BC4\u6D4B\u65B9\u5F0F\u2014\u2014<strong>\u7528\u5927\u6A21\u578B\u4F5C\u4E3A\u88C1\u5224\uFF08LLM as Judge\uFF09</strong> \uFF0C\u5BF9\u6A21\u578B\u7684\u5F00\u653E\u6027\u56DE\u7B54\u8FDB\u884C\u8D28\u91CF\u8BC4\u4F30\u3002\u8FD9\u79CD\u65B9\u5F0F\u5C24\u5176\u9002\u5408\u6CA1\u6709\u6807\u51C6\u7B54\u6848\u7684\u4EFB\u52A1\uFF0C\u5982\u95EE\u7B54\u751F\u6210\u3001\u521B\u610F\u5199\u4F5C\u3001\u5BF9\u8BDD\u8FDE\u8D2F\u6027\u3001\u5B89\u5168\u6027\u5224\u65AD\u7B49\u3002</p><p>\u4F7F\u7528\u88C1\u5224\u6A21\u578B\u8BC4\u6D4B\u65F6\uFF0C<strong>\u63D0\u793A\u8BCD\u7684\u8BBE\u8BA1</strong>\u662F\u51B3\u5B9A\u7ED3\u679C\u51C6\u786E\u6027\u7684\u5173\u952E\u3002\u8FD9\u90E8\u5206\u5DE5\u4F5C\u9700\u8981\u4F60\u81EA\u884C\u7F16\u5199\u8BC4\u6D4B\u63D0\u793A\u8BCD\uFF0C\u5E76\u8C03\u7528\u5927\u6A21\u578B\u63A5\u53E3\uFF0C\u8BA9\u88C1\u5224\u6A21\u578B\u5BF9\u9884\u671F\u7B54\u6848\u548C\u6A21\u578B\u751F\u6210\u7B54\u6848\u8FDB\u884C\u5BF9\u6BD4\u8BC4\u5224\u3002\u5177\u4F53\u6B65\u9AA4\u5982\u4E0B\uFF1A</p><ol><li><p><strong>\u5B9A\u4E49\u8BC4\u6D4B\u7EF4\u5EA6</strong>\uFF1A\u660E\u786E\u8981\u8BC4\u4F30\u6A21\u578B\u7684\u54EA\u4E9B\u65B9\u9762\uFF0C\u4F8B\u5982\u76F8\u5173\u6027\u3001\u51C6\u786E\u6027\u3001\u5B8C\u6574\u6027\u3001\u53CB\u597D\u5EA6\u3001\u5B89\u5168\u6027\u7B49\uFF0C\u5E76\u4E3A\u6BCF\u4E2A\u7EF4\u5EA6\u7ED9\u51FA\u6E05\u6670\u7684\u5B9A\u4E49\u3002</p></li><li><p><strong>\u8BBE\u8BA1\u8BC4\u5206\u91CF\u8868</strong>\uFF1A\u4E3A\u6BCF\u4E2A\u7EF4\u5EA6\u8BBE\u5B9A\u5177\u4F53\u7684\u5206\u6570\u523B\u5EA6\uFF08\u5982 1~5 \u5206\uFF09\uFF0C\u660E\u786E\u6BCF\u4E2A\u5206\u6570\u5BF9\u5E94\u7684\u8868\u73B0\u63CF\u8FF0\uFF0C\u907F\u514D\u4F7F\u7528\u201C\u597D/\u4E2D/\u5DEE\u201D\u7B49\u6A21\u7CCA\u8868\u8FF0\u3002</p></li><li><p><strong>\u7F16\u5199\u88C1\u5224\u63D0\u793A\u8BCD</strong>\uFF1A\u5C06\u8BC4\u6D4B\u7EF4\u5EA6\u548C\u8BC4\u5206\u89C4\u5219\u5D4C\u5165\u63D0\u793A\u8BCD\u4E2D\uFF0C\u660E\u786E\u544A\u77E5\u88C1\u5224\u6A21\u578B\u201C\u4F60\u7684\u4EFB\u52A1\u662F\u4EC0\u4E48\u201D\u201C\u6309\u7167\u4EC0\u4E48\u6807\u51C6\u6253\u5206\u201D\u201C\u8F93\u51FA\u683C\u5F0F\u662F\u4EC0\u4E48\u201D\u3002\u53EF\u4EE5\u52A0\u5165\u5C11\u6837\u672C\u793A\u4F8B\uFF08few-shot\uFF09\u6765\u7A33\u5B9A\u88C1\u5224\u884C\u4E3A\u3002</p></li><li><p><strong>\u7F16\u5199\u8BC4\u6D4B\u811A\u672C</strong>\uFF1A\u81EA\u884C\u7F16\u5199\u811A\u672C\uFF0C\u4F9D\u6B21\u5B8C\u6210\uFF1A\u52A0\u8F7D\u5F85\u8BC4\u6D4B\u6A21\u578B\u548C\u88C1\u5224\u6A21\u578B\uFF08\u6216\u8C03\u7528 API\uFF09\u2192 \u8BFB\u53D6\u6D4B\u8BD5\u95EE\u9898\u96C6 \u2192 \u7528\u5F85\u8BC4\u6D4B\u6A21\u578B\u751F\u6210\u56DE\u7B54 \u2192 \u7528\u88C1\u5224\u6A21\u578B\u6839\u636E\u8BBE\u8BA1\u7684\u63D0\u793A\u8BCD\u5BF9\u6BCF\u4E2A\u56DE\u7B54\u6253\u5206 \u2192 \u6C47\u603B\u5206\u6570\uFF0C\u751F\u6210\u8BC4\u6D4B\u62A5\u544A\u3002</p></li><li><p><strong>\u9A8C\u8BC1\u4E0E\u8FED\u4EE3</strong>\uFF1A\u4EBA\u5DE5\u62BD\u68C0\u90E8\u5206\u88C1\u5224\u6253\u5206\u7ED3\u679C\uFF0C\u68C0\u9A8C\u8BC4\u5206\u7684\u5408\u7406\u6027\uFF0C\u5FC5\u8981\u65F6\u8C03\u6574\u63D0\u793A\u8BCD\u6216\u8BC4\u5206\u6807\u51C6\uFF0C\u91CD\u590D\u8BC4\u6D4B\u76F4\u81F3\u7A33\u5B9A\u53EF\u9760\u3002</p></li></ol><h2 id="\u4E94\u3001\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u4E94\u3001\u603B\u7ED3" aria-hidden="true">#</a> \u4E94\u3001\u603B\u7ED3</h2><p>\u672C\u6587\u5E26\u5927\u5BB6\u7CFB\u7EDF\u68B3\u7406\u4E86\u5927\u6A21\u578B\u8BC4\u6D4B\u7684\u5B8C\u6574\u4F53\u7CFB\u3002\u4ECE\u201C\u4E3A\u4EC0\u4E48\u9700\u8981\u8BC4\u6D4B\u201D\u5165\u624B\uFF0C\u8BA4\u8BC6\u5230\u8BC4\u6D4B\u662F\u6A21\u578B\u9009\u578B\u3001\u8FED\u4EE3\u4F18\u5316\u548C\u5408\u89C4\u4E0A\u7EBF\u7684\u51B3\u7B56\u57FA\u77F3\uFF1B\u63A5\u7740\u4ECB\u7ECD\u4E86\u4E09\u79CD\u4E3B\u6D41\u8BC4\u6D4B\u65B9\u6CD5\u2014\u2014\u4EBA\u5DE5\u8BC4\u6D4B\u3001\u6570\u636E\u96C6\u8BC4\u6D4B\u548C\u5927\u6A21\u578B\u81EA\u52A8\u5316\u8BC4\u6D4B\uFF0C\u5404\u6709\u9002\u7528\u573A\u666F\uFF1B\u7136\u540E\u8BE6\u7EC6\u5217\u4E3E\u4E86\u901A\u7528\u77E5\u8BC6\u3001\u6570\u5B66\u63A8\u7406\u3001\u4EE3\u7801\u751F\u6210\u3001\u7EFC\u5408\u8003\u8BD5\u7B49\u7EF4\u5EA6\u7684\u4EE3\u8868\u6027\u6570\u636E\u96C6\uFF08MMLU\u3001C-Eval\u3001GSM8K\u3001HumanEval\u3001SWE-Bench \u7B49\uFF09\uFF0C\u8FD9\u4E9B\u6784\u6210\u4E86\u5927\u6A21\u578B\u80FD\u529B\u7684\u201C\u5168\u666F\u4F53\u68C0\u5355\u201D\uFF1B\u6700\u540E\uFF0C\u5728\u5DE5\u5177\u5C42\u9762\u533A\u5206\u4E86\u4E24\u79CD\u573A\u666F\uFF1A\u6570\u636E\u96C6\u6D4B\u8BD5\uFF08\u542B\u516C\u5F00\u6570\u636E\u96C6\u548C\u7528\u6237\u81EA\u5B9A\u4E49\u6570\u636E\u96C6\uFF09\u53EF\u4F7F\u7528 EvalScope \u4E00\u7AD9\u5F0F\u5B8C\u6210\uFF0C\u800C\u5927\u6A21\u578B\u8BC4\u6D4B\u4E2D\u7684\u63D0\u793A\u8BCD\u8BBE\u8BA1\uFF08\u5982\u88C1\u5224\u6A21\u578B\u8BC4\u6D4B\uFF09\u5219\u9700\u8981\u7528\u6237\u81EA\u5B9A\u4E49\u6807\u51C6\u5E76\u7F16\u5199\u8BC4\u6D4B\u811A\u672C\u3002</p><p>\u5927\u6A21\u578B\u8BC4\u6D4B\u548C\u8BAD\u7EC3\u4E00\u6837\uFF0C\u662F\u4E00\u95E8\u5B9E\u8DF5\u6027\u5F88\u5F3A\u7684\u6280\u80FD\uFF0C\u9700\u8981\u5728\u771F\u5B9E\u573A\u666F\u4E2D\u4E0D\u65AD\u79EF\u7D2F\u7ECF\u9A8C\u3002\u5E0C\u671B\u672C\u6587\u80FD\u591F\u5E2E\u52A9\u5927\u5BB6\u5EFA\u7ACB\u8D77\u7CFB\u7EDF\u7684\u8BC4\u6D4B\u601D\u7EF4\uFF0C\u4ECE\u201C\u4E3B\u89C2\u611F\u89C9\u201D\u8D70\u5411\u201C\u6570\u636E\u9A71\u52A8\u201D\u3002\u5173\u4E8E\u5927\u6A21\u578B\u8BC4\u6D4B\u7684\u65B9\u6CD5\u8BBA\u4E0E\u6570\u636E\u96C6\u5C31\u5206\u4EAB\u5230\u8FD9\u91CC\u4E86\u3002\u63A5\u4E0B\u6765\u5C31\u8BE5\u771F\u6B63\u52A8\u624B\u5B9E\u64CD\u4E86\u2014\u2014<strong>\u4E0B\u4E00\u671F\u6587\u7AE0</strong>\u7B14\u8005\u5C06\u5E26\u5927\u5BB6\u5B9E\u6218\u5206\u4EAB\u4E24\u79CD\u8BC4\u6D4B\u5DE5\u5177\u7684\u5177\u4F53\u4F7F\u7528\uFF1A<strong>EvalScope \u7684\u5B8C\u6574\u64CD\u4F5C\u6D41\u7A0B</strong>\uFF08\u73AF\u5883\u5B89\u88C5\u3001\u516C\u5F00\u6570\u636E\u96C6\u8BC4\u6D4B\u3001\u81EA\u5B9A\u4E49\u6570\u636E\u96C6\u8BC4\u6D4B\uFF09\u4EE5\u53CA<strong>\u88C1\u5224\u6A21\u578B\u8BC4\u6D4B\u811A\u672C\u7684\u7F16\u5199\u793A\u4F8B</strong>\uFF08\u5982\u4F55\u8BBE\u8BA1\u63D0\u793A\u8BCD\u3001\u8C03\u7528 API\u3001\u6C47\u603B\u5206\u6570\uFF09\uFF0C\u5927\u5BB6\u656C\u8BF7\u671F\u5F85\uFF01</p><p>\u9664\u5927\u6A21\u578B\u8BAD\u7EC3\u5916\uFF0C\u7B14\u8005\u4E5F\u5728\u540C\u6B65\u66F4\u65B0\u300A\u6DF1\u5165\u6D45\u51FALangChain&amp;LangGraph AI Agent \u667A\u80FD\u4F53\u5F00\u53D1\u300B\u4E13\u680F\uFF0C\u8981\u8BF4\u660E\u8BE5\u4E13\u680F\u9002\u5408\u6240\u6709\u5BF9 LangChain \u611F\u5174\u8DA3\u7684\u5B66\u4E60\u8005\uFF0C\u65E0\u8BBA\u4E4B\u524D\u662F\u5426\u63A5\u89E6\u8FC7 LangChain\u3002\u8BE5\u4E13\u680F\u57FA\u4E8E\u7B14\u8005\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u7684\u6DF1\u5EA6\u4F7F\u7528\u7ECF\u9A8C\uFF0C\u7CFB\u7EDF\u8BB2\u89E3\u4E86\u4F7F\u7528LangChain/LangGraph\u5982\u4F55\u5F00\u53D1\u667A\u80FD\u4F53\uFF0C\u76EE\u524D\u5DF2\u66F4\u65B0 45 \u8BB2\uFF0C\u5E76\u6301\u7EED\u8865\u5145\u5B9E\u6218\u4E0E\u62D3\u5C55\u5185\u5BB9\u3002\u6B22\u8FCE\u611F\u5174\u8DA3\u7684\u540C\u5B66\u5173\u6CE8\u7B14\u8005\u7684\u6398\u91D1\u8D26\u53F7\u4E0E\u4E13\u680F\uFF0C\u4E5F\u53EF\u5173\u6CE8\u7B14\u8005\u7684\u540C\u540D\u5FAE\u4FE1\u516C\u4F17\u53F7<strong>\u5927\u6A21\u578B\u771F\u597D\u73A9</strong>\uFF0C\u6BCF\u671F\u5206\u4EAB\u6D89\u53CA\u7684\u4EE3\u7801\u5747\u53EF\u5728\u516C\u4F17\u53F7\u79C1\u4FE1: <strong>LangChain\u667A\u80FD\u4F53\u5F00\u53D1</strong>\u514D\u8D39\u83B7\u53D6\u3002</p>',49),s=[t];function i(p,l){return n(),r("div",null,s)}var d=a(e,[["render",i],["__file","ai-llm-training-evaluation.html.vue"]]);export{d as default};
